#![allow(non_snake_case)]

use std::io::Write;

use anyhow::{bail, Context, Result};
use arcstr::{literal, ArcStr};
use metamodelica::{list, List};

use openmodelica_simcode_types::SimCode;
use openmodelica_util::Error;

pub fn serialize(code: SimCode::SimCode) -> Result<ArcStr> {
    for jac in &*code.jacobianMatrices {
        // Pick sparsity and coloring depending on the isAdjoint flag.
        let (pattern, colorList) = if jac.isAdjoint {
            // For the adjoint Jacobian a row coloring must exist.
            if matches!(&*jac.coloredRows, List::Nil) {
                Error::addMessage(
                    Error::INTERNAL_ERROR.clone(),
                    list![literal!(
                        "SerializeSparsityPattern.serialize failed because no row coloring for the adjoint jacobian exists."
                    )],
                )?;
                bail!("fail");
            }
            (&jac.sparsityT, &jac.coloredRows)
        } else {
            (&jac.sparsity, &jac.coloredCols)
        };

        if matches!(&**pattern, List::Nil) {
            continue;
        }

        let fname = format!("{}_Jac{}.bin", code.fileNamePrefix, jac.matrixName);
        // columnPointers = 0 :: per-column non-zero counts; rowIndices =
        // the concatenation of every column's row-index list (matching the
        // `listArray(...)` constructions in the .mo).
        let mut colPtrs: Vec<i32> = vec![0];
        let mut rowInds: Vec<i32> = Vec::new();
        for (_, rows) in &**pattern {
            colPtrs.push(rows.len());
            rowInds.extend((&**rows).into_iter().copied());
        }
        serializeJacobian(&fname, &colPtrs, &rowInds)?;
        for color in &**colorList {
            let columns: Vec<i32> = (&**color).into_iter().copied().collect();
            serializeColor(&fname, &columns)?;
        }
    }
    Ok(literal!(""))
}

// *********************
// write to binary stuff
// *********************

/// `serializeJ` from the .mo `Include` annotation: create `name` ("wb") and
/// write the leadindex (the running sum over `colPtrs`) followed by the row
/// indices, each as a native-endian u32.
fn serializeJacobian(name: &str, colPtrs: &[i32], rowInds: &[i32]) -> Result<()> {
    let file = std::fs::File::create(name)
        .with_context(|| format!("Could not open sparsity pattern file {name}."))?;
    let mut out = std::io::BufWriter::new(file);
    // Compute and write sparsePattern->leadindex.
    let mut j: u32 = 0;
    for &c in colPtrs {
        j = j.wrapping_add(c as u32);
        out.write_all(&j.to_ne_bytes())
            .with_context(|| format!("Error while writing sparsePattern->leadindex to {name}."))?;
    }
    // Write sparsePattern->index.
    for &r in rowInds {
        out.write_all(&(r as u32).to_ne_bytes())
            .with_context(|| format!("Error while writing sparsePattern->index to {name}."))?;
    }
    out.flush()
        .with_context(|| format!("Error while writing sparsity pattern file {name}."))?;
    Ok(())
}

/// `serializeC` from the .mo `Include` annotation: append ("ab") one color's
/// column indices to the pattern file, each as a native-endian u32.
fn serializeColor(name: &str, columns: &[i32]) -> Result<()> {
    let file = std::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(name)
        .with_context(|| format!("Could not open sparsity pattern file {name}."))?;
    let mut out = std::io::BufWriter::new(file);
    // Write sparsePattern->colorCols.
    for &c in columns {
        out.write_all(&(c as u32).to_ne_bytes())
            .with_context(|| format!("Error while writing sparsePattern->colorCols to {name}."))?;
    }
    out.flush()
        .with_context(|| format!("Error while writing sparsity pattern file {name}."))?;
    Ok(())
}
